PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_user_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_user_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "auth_user" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "first_name" varchar(150) NOT NULL);
CREATE TABLE IF NOT EXISTS "quiz_analyticsevent" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "event_type" varchar(50) NOT NULL, "metadata" text NOT NULL CHECK ((JSON_VALID("metadata") OR "metadata" IS NULL)), "timestamp" datetime NOT NULL, "career_id" bigint NULL REFERENCES "quiz_career" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_assessment" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "session_id" varchar(100) NOT NULL UNIQUE, "top_category" varchar(20) NOT NULL, "scores" text NOT NULL CHECK ((JSON_VALID("scores") OR "scores" IS NULL)), "results" text NOT NULL CHECK ((JSON_VALID("results") OR "results" IS NULL)), "completed_at" datetime NOT NULL, "user_id" integer NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_career" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "title" varchar(200) NOT NULL UNIQUE, "primary_category" varchar(20) NOT NULL, "secondary_categories" text NOT NULL CHECK ((JSON_VALID("secondary_categories") OR "secondary_categories" IS NULL)), "description" text NOT NULL, "detailed_description" text NOT NULL, "average_salary_min" integer NULL, "average_salary_max" integer NULL, "job_growth_rate" real NULL, "career_outlook" text NOT NULL, "required_education" varchar(200) NOT NULL, "certifications" text NOT NULL CHECK ((JSON_VALID("certifications") OR "certifications" IS NULL)), "typical_companies" text NOT NULL CHECK ((JSON_VALID("typical_companies") OR "typical_companies" IS NULL)), "work_environment" text NOT NULL, "average_rating" real NOT NULL);
CREATE TABLE IF NOT EXISTS "quiz_forumcategory" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(100) NOT NULL UNIQUE, "description" text NOT NULL, "icon" varchar(50) NOT NULL);
CREATE TABLE IF NOT EXISTS "quiz_loginattempt" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "username" varchar(150) NOT NULL, "ip_address" char(39) NULL, "success" bool NOT NULL, "timestamp" datetime NOT NULL, "reason" varchar(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "quiz_mentor" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "bio" text NOT NULL, "years_experience" integer NOT NULL, "hourly_rate" integer NULL, "availability" text NOT NULL CHECK ((JSON_VALID("availability") OR "availability" IS NULL)), "average_rating" real NOT NULL, "is_verified" bool NOT NULL, "created_at" datetime NOT NULL, "specialization_id" bigint NULL REFERENCES "quiz_career" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL UNIQUE REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_skill" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(100) NOT NULL UNIQUE, "category" varchar(50) NOT NULL, "description" text NOT NULL, "difficulty_level" varchar(20) NOT NULL, "learning_resources" text NOT NULL CHECK ((JSON_VALID("learning_resources") OR "learning_resources" IS NULL)));
CREATE TABLE IF NOT EXISTS "quiz_skill_careers" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "skill_id" bigint NOT NULL REFERENCES "quiz_skill" ("id") DEFERRABLE INITIALLY DEFERRED, "career_id" bigint NOT NULL REFERENCES "quiz_career" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_usersuccessstory" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "title" varchar(300) NOT NULL, "story" text NOT NULL, "current_role" varchar(200) NOT NULL, "years_in_career" integer NOT NULL, "challenges_faced" text NOT NULL, "tips_for_others" text NOT NULL, "image" varchar(100) NULL, "featured" bool NOT NULL, "created_at" datetime NOT NULL, "author_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "career_id" bigint NOT NULL REFERENCES "quiz_career" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_userskill" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "proficiency_level" varchar(20) NOT NULL, "years_of_experience" real NOT NULL, "acquired_at" datetime NOT NULL, "skill_id" bigint NOT NULL REFERENCES "quiz_skill" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_userprofile" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "bio" text NULL, "profile_picture" varchar(100) NULL, "location" varchar(100) NOT NULL, "phone" varchar(15) NOT NULL, "current_role" varchar(100) NOT NULL, "experience_level" varchar(20) NOT NULL, "preferred_notification" varchar(20) NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "user_id" integer NOT NULL UNIQUE REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_mentorrequest" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "status" varchar(20) NOT NULL, "message" text NOT NULL, "requested_at" datetime NOT NULL, "scheduled_date" datetime NULL, "mentee_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "mentor_id" bigint NOT NULL REFERENCES "quiz_mentor" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_joblisting" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "title" varchar(200) NOT NULL, "company" varchar(200) NOT NULL, "location" varchar(200) NOT NULL, "salary_min" integer NULL, "salary_max" integer NULL, "description" text NOT NULL, "job_url" varchar(200) NOT NULL, "source" varchar(50) NOT NULL, "posted_at" datetime NOT NULL, "expires_at" datetime NULL, "career_id" bigint NOT NULL REFERENCES "quiz_career" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_joblisting_required_skills" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "joblisting_id" bigint NOT NULL REFERENCES "quiz_joblisting" ("id") DEFERRABLE INITIALLY DEFERRED, "skill_id" bigint NOT NULL REFERENCES "quiz_skill" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_forumreply" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content" text NOT NULL, "upvotes" integer NOT NULL, "is_solution" bool NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "author_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "post_id" bigint NOT NULL REFERENCES "quiz_forumpost" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_careerroadmap" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "timeline_months" integer NOT NULL, "steps" text NOT NULL CHECK ((JSON_VALID("steps") OR "steps" IS NULL)), "estimated_cost" integer NULL, "resources" text NOT NULL CHECK ((JSON_VALID("resources") OR "resources" IS NULL)), "success_tips" text NOT NULL CHECK ((JSON_VALID("success_tips") OR "success_tips" IS NULL)), "career_id" bigint NOT NULL UNIQUE REFERENCES "quiz_career" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_careerbookmark" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "bookmarked_at" datetime NOT NULL, "notes" text NOT NULL, "career_id" bigint NOT NULL REFERENCES "quiz_career" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "quiz_learninggoal" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "target_proficiency" varchar(20) NOT NULL, "estimated_hours" integer NOT NULL, "deadline" date NULL, "completed" bool NOT NULL, "created_at" datetime NOT NULL, "skill_id" bigint NOT NULL REFERENCES "quiz_skill" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_usercareergoal" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "target_proficiency_level" varchar(20) NOT NULL, "target_timeline_months" integer NOT NULL, "notes" text NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "target_career_id" bigint NOT NULL REFERENCES "quiz_career" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL UNIQUE REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_learningprogress" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "hours_completed" real NOT NULL, "courses_completed" text NOT NULL CHECK ((JSON_VALID("courses_completed") OR "courses_completed" IS NULL)), "milestone_reached" varchar(255) NOT NULL, "completed_percentage" real NOT NULL, "logged_at" datetime NOT NULL, "learning_goal_id" bigint NOT NULL REFERENCES "quiz_learninggoal" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_careerpivotanalysis" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "current_career_type" varchar(255) NOT NULL, "analysis" text NOT NULL CHECK ((JSON_VALID("analysis") OR "analysis" IS NULL)), "ai_generated" bool NOT NULL, "created_at" datetime NOT NULL, "target_career_id" bigint NOT NULL REFERENCES "quiz_career" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "quiz_forumpost" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "title" varchar(300) NOT NULL, "content" text NOT NULL, "views" integer NOT NULL, "upvotes" integer NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "author_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "career_id" bigint NULL REFERENCES "quiz_career" ("id") DEFERRABLE INITIALLY DEFERRED, "category_id" bigint NULL REFERENCES "quiz_forumcategory" ("id") DEFERRABLE INITIALLY DEFERRED, "is_closed" bool NOT NULL, "closed_by_id" integer NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "closed_at" datetime NULL, "close_reason" text NULL);
DELETE FROM sqlite_sequence;
